input.command:
kubectl exec -n mongodb mongodb-replica-0 -- mongosh \
  -u admin-user -p admin123password \
  --authenticationDatabase admin \
  --quiet \
  --eval "
    const status = rs.status();
    print('RS name: ' + status.set);
    print('Members:');
    status.members.forEach(m => print('  ' + m.name + ' -> ' + m.stateStr));
  " 2>&1

