  -u admin-user -p admin123password \
  --authenticationDatabase admin \
  --quiet \
  --eval "
    const s = rs.status();
    print('Replica set: ' + s.set);
    s.members.forEach(m => print('  ' + m.name + '  state=' + m.stateStr));
  " 2>&1

